import React from 'react';
import './BingoBoard.css';

function BingoBoard({ calledNumbers }) {
  // Generate numbers for each column - 15 rows per column
  const bingoColumns = {
    B: Array.from({ length: 15 }, (_, i) => i + 1),
    I: Array.from({ length: 15 }, (_, i) => i + 16),
    N: Array.from({ length: 15 }, (_, i) => i + 31),
    G: Array.from({ length: 15 }, (_, i) => i + 46),
    O: Array.from({ length: 15 }, (_, i) => i + 61)
  };

  // Check if a number has been called
  const isNumberCalled = (number) => {
    return calledNumbers.includes(number);
  };

  // Inline styles for debugging
  const boardContainerStyle = {
    padding: '15px',
    marginBottom: '20px',
    background: 'rgba(0, 0, 0, 0.3)',
    borderRadius: '15px',
    overflowX: 'auto'
  };

  const headerStyle = {
    display: 'grid',
    gridTemplateColumns: 'repeat(5, 1fr)',
    gap: '4px',
    marginBottom: '8px'
  };

  const columnHeaderStyle = {
    textAlign: 'center',
    fontWeight: 'bold',
    fontSize: '1.2rem',
    padding: '8px',
    color: '#ffd700'
  };

  const rowStyle = {
    display: 'grid',
    gridTemplateColumns: 'repeat(5, 1fr)',
    gap: '4px',
    marginBottom: '4px'
  };

  const cellStyle = (called) => ({
    aspectRatio: '1',
    background: called ? 'linear-gradient(135deg, #ffd700, #ffb347)' : 'rgba(255, 255, 255, 0.1)',
    borderRadius: '6px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontWeight: 'bold',
    fontSize: '0.8rem',
    color: called ? '#1a1a2e' : 'white',
    cursor: 'pointer',
    border: '1px solid rgba(255, 255, 255, 0.1)',
    padding: '4px'
  });

  const statsStyle = {
    marginTop: '15px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '8px 12px',
    background: 'rgba(0, 0, 0, 0.3)',
    borderRadius: '8px',
    fontSize: '0.85rem'
  };

  return (
    <div style={boardContainerStyle}>
      <h3 style={{ textAlign: 'center', marginBottom: '15px', color: '#ffd700' }}>🎯 BINGO Number Board</h3>
      
      {/* Column Headers */}
      <div style={headerStyle}>
        <div style={columnHeaderStyle}>B</div>
        <div style={columnHeaderStyle}>I</div>
        <div style={columnHeaderStyle}>N</div>
        <div style={columnHeaderStyle}>G</div>
        <div style={columnHeaderStyle}>O</div>
      </div>
      
      {/* Board Body - 15 rows */}
      <div>
        {[...Array(15)].map((_, rowIndex) => (
          <div key={rowIndex} style={rowStyle}>
            {['B', 'I', 'N', 'G', 'O'].map(letter => {
              const number = bingoColumns[letter][rowIndex];
              const called = isNumberCalled(number);
              return (
                <div
                  key={`${letter}-${number}`}
                  style={cellStyle(called)}
                  title={`${letter}${number} - ${called ? 'Called ✓' : 'Not Called'}`}
                >
                  {number}
                </div>
              );
            })}
          </div>
        ))}
      </div>
      
      {/* Statistics */}
      <div style={statsStyle}>
        <span>📊 Called: {calledNumbers.length}/75</span>
        <span style={{ background: 'rgba(255, 215, 0, 0.2)', padding: '4px 10px', borderRadius: '20px', color: '#ffd700' }}>
          {calledNumbers.length === 0 && '🎯 Waiting...'}
          {calledNumbers.length > 0 && calledNumbers.length < 75 && `🎲 ${Math.round((calledNumbers.length / 75) * 100)}% Complete`}
          {calledNumbers.length === 75 && '🎉 BINGO COMPLETE!'}
        </span>
      </div>
    </div>
  );
}

export default BingoBoard;
